mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, T1.* FROM ( SELECT O.ORDER_TOTAL_PRICE, O.ORDER_DATE, O.ORDER_ID, P.PRODUCT_NAME, P.PRODUCT_PHOTO1 AS PHOTO1, NVL(S.DELIVERY_STATUS, '결제완료') AS DELIVERY_STATUS, OD.DETAIL_PRICE, OD.DETAIL_ID AS DETAIL_ID, NVL(OD.CANCEL_YN, 'N') AS CANCEL_YN, NVL(OD.CANCEL_STATUS, 'NONE') AS CANCEL_STATUS, TO_CHAR(OD.CANCEL_REQUEST_DATE, 'YYYY-MM-DD') AS CANCEL_REQUEST_DATE_STR, OD.CANCEL_REASON, CASE WHEN NVL(OD.CANCEL_STATUS, 'NONE') = 'PENDING' THEN '취소요청' WHEN NVL(OD.CANCEL_STATUS, 'NONE') = 'APPROVED' THEN '취소완료' WHEN NVL(OD.CANCEL_STATUS, 'NONE') = 'REJECTED' THEN '취소반려' ELSE '정상' END AS DETAIL_CANCEL_STATUS_LABEL FROM ORDERS O JOIN ORDER_DETAIL OD ON O.ORDER_ID = OD.ORDER_ID JOIN PRODUCT P ON OD.PRODUCT_ID = P.PRODUCT_ID LEFT JOIN DELIVERY D ON O.ORDER_ID = D.ORDER_ID LEFT JOIN ( SELECT S1.DELIVERY_ID, S1.DELIVERY_STATUS FROM STATUS S1 WHERE S1.DNUM = ( SELECT MAX(S2.DNUM) FROM STATUS S2 WHERE S2.DELIVERY_ID = S1.DELIVERY_ID ) ) S ON D.DELIVERY_ID = S.DELIVERY_ID WHERE O.MEMBER_NO = #{memberNo}
AND O.ORDER_DATE >= SYSDATE - #{period}
AND O.ORDER_DATE BETWEEN #{startDate} AND #{endDate}
ORDER BY O.ORDER_DATE DESC, OD.DETAIL_ID DESC ) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM ORDERS O
JOIN ORDER_DETAIL OD
  ON O.ORDER_ID = OD.ORDER_ID
JOIN PRODUCT P
  ON OD.PRODUCT_ID = P.PRODUCT_ID
WHERE O.MEMBER_NO = #{memberNo}

    AND O.ORDER_DATE >= SYSDATE - #{period}


    AND O.ORDER_DATE BETWEEN #{startDate} AND #{endDate}

SELECT *
FROM (
    SELECT ROWNUM AS RNUM, T1.*
    FROM (
        SELECT
            R.PRODUCT_ID,
            R.VIEWED_DATE,
            P.PRODUCT_NAME,
            P.PRODUCT_PHOTO1,
            P.PRODUCT_PRICE
        FROM RECENTLY_VIEWED R
        JOIN PRODUCT P
          ON P.PRODUCT_ID = R.PRODUCT_ID
        WHERE MEMBER_NO = #{memberNo}

            AND VIEWED_DATE >= SYSDATE - #{period}


            AND VIEWED_DATE BETWEEN #{startDate} AND #{endDate}

        ORDER BY VIEWED_DATE DESC
    ) T1
)
WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM RECENTLY_VIEWED
WHERE MEMBER_NO = #{memberNo}

    AND VIEWED_DATE >= SYSDATE - #{period}


    AND VIEWED_DATE BETWEEN #{startDate} AND #{endDate}

SELECT *
FROM (
    SELECT ROWNUM AS RNUM, T1.*
    FROM (
        SELECT *
        FROM INQUIRY
        WHERE MEMBER_NO = #{memberNo}
        ORDER BY INQUIRY_REG_DATE DESC
    ) T1
)
WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM INQUIRY
WHERE MEMBER_NO = #{memberNo}

