SELECT COUNT(*)
  FROM ORDER_DETAIL
 WHERE DETAIL_ID = #{detailId}
   AND ORDER_ID = #{orderId}
   AND NVL(CANCEL_YN, 'N') = 'Y'

SELECT DETAIL_PRICE
  FROM ORDER_DETAIL
 WHERE DETAIL_ID = #{detailId}
   AND ORDER_ID = #{orderId}

select.update:
UPDATE ORDER_DETAIL
   SET CANCEL_YN = 'Y'
 WHERE DETAIL_ID = #{detailId}
   AND ORDER_ID = #{orderId}
   AND NVL(CANCEL_YN, 'N') = 'N'

UPDATE ORDERS
   SET ORDER_TOTAL_PRICE = 
   CASE WHEN ORDER_TOTAL_PRICE - #{cancelAmount} < 0 THEN 0
        ELSE ORDER_TOTAL_PRICE - #{cancelAmount}
   END
 WHERE ORDER_ID = #{orderId}

UPDATE ORDERS
   SET ORDER_CANCEL_YN = 'Y',
       CANCEL_REQUEST_DATE = SYSDATE,
       CANCEL_REASON = #{cancelReason},
       CANCEL_STATUS = 'PENDING'
 WHERE MEMBER_NO = #{memberNo}
   AND ORDER_ID = #{orderId}
   AND NOT EXISTS (
        SELECT 1
          FROM ORDER_DETAIL
         WHERE ORDER_ID = #{orderId}
           AND NVL(CANCEL_YN, 'N') = 'N'
   )

UPDATE MEMBER 
SET MEMBER_ACTIVE_YN = 'N'
WHERE MEMBER_NO = #{memberNo}

UPDATE MEMBER
SET EMAIL = #{email}, 
MEMBER_NAME= #{memberName}, 
MEMBER_ADDRESS =  #{address},
PHONE = #{phone}
WHERE MEMBER_NO = #{memberNo}

