WHERE DETAIL_ID = #{detailId}
  AND ORDER_ID = #{orderId}
  AND NVL(CANCEL_STATUS, 'NONE') IN ('PENDING', 'APPROVED')

select.update:
UPDATE ORDER_DETAIL
SET CANCEL_STATUS = 'PENDING',
    CANCEL_REQUEST_DATE = SYSDATE,
    CANCEL_REASON = #{cancelReason}
WHERE DETAIL_ID = #{detailId}
  AND ORDER_ID = #{orderId}
  AND NVL(CANCEL_STATUS, 'NONE') NOT IN ('PENDING', 'APPROVED')

UPDATE MEMBER
SET MEMBER_ACTIVE_YN = 'N'
WHERE MEMBER_NO = #{memberNo}

UPDATE MEMBER
